xccdf-1.2:Rule.xccdf-1.2:fix:
include install_aide

class install_aide {
  package { 'aide':
    ensure => 'installed',
  }
}

include install_binutils

class install_binutils {
  package { 'binutils':
    ensure => 'installed',
  }
}

include enable_rsyslog

class enable_rsyslog {
  service {'rsyslog':
    enable => true,
    ensure => 'running',
  }
}

include enable_firewalld

class enable_firewalld {
  service {'firewalld':
    enable => true,
    ensure => 'running',
  }
}

include disable_autofs

class disable_autofs {
  service {'autofs':
    enable => false,
    ensure => 'stopped',
  }
}

include install_psacct

class install_psacct {
  package { 'psacct':
    ensure => 'installed',
  }
}

include enable_psacct

class enable_psacct {
  service {'psacct':
    enable => true,
    ensure => 'running',
  }
}

include disable_dhcpd

class disable_dhcpd {
  service {'dhcpd':
    enable => false,
    ensure => 'stopped',
  }
}

include remove_nfs-utils

class remove_nfs-utils {
  package { 'nfs-utils':
    ensure => 'purged',
  }
}

include disable_nfs-server

class disable_nfs-server {
  service {'nfs-server':
    enable => false,
    ensure => 'stopped',
  }
}

include install_chrony

class install_chrony {
  package { 'chrony':
    ensure => 'installed',
  }
}

include install_ntp

class install_ntp {
  package { 'ntp':
    ensure => 'installed',
  }
}

include remove_rsync

class remove_rsync {
  package { 'rsync':
    ensure => 'purged',
  }
}

include remove_ypbind

class remove_ypbind {
  package { 'ypbind':
    ensure => 'purged',
  }
}

include remove_telnet-server

class remove_telnet-server {
  package { 'telnet-server':
    ensure => 'purged',
  }
}

include remove_tftp-server

class remove_tftp-server {
  package { 'tftp-server':
    ensure => 'purged',
  }
}

include remove_tftp

class remove_tftp {
  package { 'tftp':
    ensure => 'purged',
  }
}

include remove_net-snmp

class remove_net-snmp {
  package { 'net-snmp':
    ensure => 'purged',
  }
}

include install_openssh-server

class install_openssh-server {
  package { 'openssh-server':
    ensure => 'installed',
  }
}

include enable_sshd

class enable_sshd {
  service {'sshd':
    enable => true,
    ensure => 'running',
  }
}

include ssh_private_key_perms

class ssh_private_key_perms {
  exec { 'sshd_priv_key':
    command => "chmod 0640 /etc/ssh/*_key",
    path    => '/bin:/usr/bin'
  }
}

include enable_auditd

class enable_auditd {
  service {'auditd':
    enable => true,
    ensure => 'running',
  }
}

